# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
import shutil
from datetime import datetime
from flask import Flask, request, jsonify, send_file, abort

app = Flask(__name__)

# Base directory where all user uploads are stored
BASE_UPLOAD_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), 'uploads'))

# Ensure the base upload directory exists
os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)


def get_user_root(user_id):
    """Get the root directory for a specific user."""
    user_root = os.path.abspath(os.path.join(BASE_UPLOAD_DIR, str(user_id)))
    os.makedirs(user_root, exist_ok=True)
    return user_root


def resolve_safe_path(user_root, relative_path):
    """
    Safely resolve a relative path within a user's root directory.
    Prevents path traversal attacks by ensuring the resolved path
    stays within the user's root directory.
    """
    if relative_path is None:
        relative_path = ''

    # Normalize the path to handle '..' and other path components
    normalized = os.path.normpath(relative_path)

    # Join with user root
    full_path = os.path.join(user_root, normalized)

    # Get the absolute path
    full_path = os.path.abspath(full_path)

    # Security check: ensure the resolved path is within the user's root
    if not full_path.startswith(os.path.abspath(user_root)):
        return None

    return full_path


def get_file_info_dict(file_path, user_root):
    """Get detailed information about a file or directory."""
    stat = os.stat(file_path)
    relative_path = os.path.relpath(file_path, user_root)
    if relative_path == '.':
        relative_path = ''

    info = {
        'name': os.path.basename(file_path) or '/',
        'path': relative_path,
        'is_directory': os.path.isdir(file_path),
        'size_bytes': stat.st_size if not os.path.isdir(file_path) else get_dir_size(file_path),
        'created': datetime.fromtimestamp(stat.st_ctime).isoformat(),
        'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
        'accessed': datetime.fromtimestamp(stat.st_atime).isoformat(),
    }

    if not os.path.isdir(file_path):
        _, ext = os.path.splitext(file_path)
        info['extension'] = ext.lstrip('.')
    else:
        info['num_items'] = len(os.listdir(file_path))

    return info


def get_dir_size(dir_path):
    """Calculate total size of a directory."""
    total_size = 0
    for dirpath, dirnames, filenames in os.walk(dir_path):
        for f in filenames:
            fp = os.path.join(dirpath, f)
            if os.path.exists(fp):
                total_size += os.path.getsize(fp)
    return total_size


def get_user_id_from_request():
    """Extract user ID from request. In production, this would use authentication."""
    user_id = request.headers.get('X-User-ID', request.args.get('user_id', 'default_user'))
    # Sanitize user_id to prevent path traversal via user_id
    user_id = os.path.basename(str(user_id))
    if not user_id:
        return None
    return user_id


@app.route('/api/files/list', methods=['GET'])
def list_directory():
    """
    List contents of a directory.
    Query params:
        - path: relative path to directory (default: root)
        - user_id: user identifier
    """
    user_id = get_user_id_from_request()
    if not user_id:
        return jsonify({'error': 'Invalid user ID'}), 400

    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')

    full_path = resolve_safe_path(user_root, relative_path)
    if full_path is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': 'Path not found'}), 404

    if not os.path.isdir(full_path):
        return jsonify({'error': 'Path is not a directory'}), 400

    items = []
    try:
        for entry in sorted(os.listdir(full_path)):
            entry_path = os.path.join(full_path, entry)
            entry_relative = os.path.relpath(entry_path, user_root)
            stat = os.stat(entry_path)
            item = {
                'name': entry,
                'path': entry_relative,
                'is_directory': os.path.isdir(entry_path),
                'size_bytes': stat.st_size if not os.path.isdir(entry_path) else 0,
                'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
            }
            if not os.path.isdir(entry_path):
                _, ext = os.path.splitext(entry)
                item['extension'] = ext.lstrip('.')
            items.append(item)
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403

    current_relative = os.path.relpath(full_path, user_root)
    if current_relative == '.':
        current_relative = ''

    # Determine parent path
    parent_path = None
    if current_relative:
        parent = os.path.dirname(current_relative)
        parent_path = parent if parent != current_relative else ''

    response = {
        'current_path': current_relative,
        'parent_path': parent_path,
        'total_items': len(items),
        'directories': [i for i in items if i['is_directory']],
        'files': [i for i in items if not i['is_directory']],
        'items': items,
    }

    return jsonify(response), 200


@app.route('/api/files/info', methods=['GET'])
def file_info():
    """
    Get detailed information about a file or directory.
    Query params:
        - path: relative path to file/directory
        - user_id: user identifier
    """
    user_id = get_user_id_from_request()
    if not user_id:
        return jsonify({'error': 'Invalid user ID'}), 400

    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')

    if not relative_path:
        return jsonify({'error': 'Path parameter is required'}), 400

    full_path = resolve_safe_path(user_root, relative_path)
    if full_path is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': 'Path not found'}), 404

    try:
        info = get_file_info_dict(full_path, user_root)
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403

    return jsonify(info), 200


@app.route('/api/files/download', methods=['GET'])
def download_file():
    """
    Download a file.
    Query params:
        - path: relative path to file
        - user_id: user identifier
    """
    user_id = get_user_id_from_request()
    if not user_id:
        return jsonify({'error': 'Invalid user ID'}), 400

    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')

    if not relative_path:
        return jsonify({'error': 'Path parameter is required'}), 400

    full_path = resolve_safe_path(user_root, relative_path)
    if full_path is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': 'File not found'}), 404

    if os.path.isdir(full_path):
        return jsonify({'error': 'Cannot download a directory. Use /api/files/download-zip for directories.'}), 400

    try:
        return send_file(
            full_path,
            as_attachment=True,
            download_name=os.path.basename(full_path)
        )
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403


@app.route('/api/files/upload', methods=['POST'])
def upload_file():
    """
    Upload a file to a specified directory.
    Form data:
        - file: the file to upload
        - path: destination directory (relative path, default: root)
    Query params:
        - user_id: user identifier
    """
    user_id = get_user_id_from_request()
    if not user_id:
        return jsonify({'error': 'Invalid user ID'}), 400

    user_root = get_user_root(user_id)

    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400

    dest_dir = request.form.get('path', '')
    dest_dir_full = resolve_safe_path(user_root, dest_dir)
    if dest_dir_full is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    os.makedirs(dest_dir_full, exist_ok=True)

    # Sanitize filename
    filename = os.path.basename(file.filename)
    if not filename:
        return jsonify({'error': 'Invalid filename'}), 400

    file_path = os.path.join(dest_dir_full, filename)
    file_path = os.path.abspath(file_path)

    # Double-check the final path is still within user root
    if not file_path.startswith(os.path.abspath(user_root)):
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    try:
        file.save(file_path)
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403

    relative_path = os.path.relpath(file_path, user_root)

    return jsonify({
        'message': 'File uploaded successfully',
        'name': filename,
        'path': relative_path,
        'size_bytes': os.path.getsize(file_path),
    }), 201


@app.route('/api/files/mkdir', methods=['POST'])
def create_directory():
    """
    Create a new directory.
    JSON body:
        - path: relative path for the new directory
    Query params:
        - user_id: user identifier
    """
    user_id = get_user_id_from_request()
    if not user_id:
        return jsonify({'error': 'Invalid user ID'}), 400

    user_root = get_user_root(user_id)
    data = request.get_json()

    if not data or 'path' not in data:
        return jsonify({'error': 'Path is required in request body'}), 400

    relative_path = data['path']
    full_path = resolve_safe_path(user_root, relative_path)
    if full_path is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    if os.path.exists(full_path):
        return jsonify({'error': 'Path already exists'}), 409

    try:
        os.makedirs(full_path, exist_ok=False)
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403
    except OSError as e:
        return jsonify({'error': str(e)}), 500

    return jsonify({
        'message': 'Directory created successfully',
        'path': os.path.relpath(full_path, user_root),
    }), 201


@app.route('/api/files/delete', methods=['DELETE'])
def delete_file():
    """
    Delete a file or directory.
    Query params:
        - path: relative path to file/directory
        - user_id: user identifier
    """
    user_id = get_user_id_from_request()
    if not user_id:
        return jsonify({'error': 'Invalid user ID'}), 400

    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')

    if not relative_path:
        return jsonify({'error': 'Path parameter is required'}), 400

    full_path = resolve_safe_path(user_root, relative_path)
    if full_path is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    # Prevent deleting the root directory itself
    if os.path.abspath(full_path) == os.path.abspath(user_root):
        return jsonify({'error': 'Cannot delete root directory'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': 'Path not found'}), 404

    try:
        if os.path.isdir(full_path):
            shutil.rmtree(full_path)
        else:
            os.remove(full_path)
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403
    except OSError as e:
        return jsonify({'error': str(e)}), 500

    return jsonify({
        'message': 'Deleted successfully',
        'path': relative_path,
    }), 200


@app.route('/api/files/search', methods=['GET'])
def search_files():
    """
    Search for files/directories by name pattern.
    Query params:
        - query: search string
        - path: directory to search in (default: root)
        - user_id: user identifier
    """
    user_id = get_user_id_from_request()
    if not user_id:
        return jsonify({'error': 'Invalid user ID'}), 400

    user_root = get_user_root(user_id)
    query = request.args.get('query', '')
    search_path = request.args.get('path', '')

    if not query:
        return jsonify({'error': 'Query parameter is required'}), 400

    full_path = resolve_safe_path(user_root, search_path)
    if full_path is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    if not os.path.exists(full_path) or not os.path.isdir(full_path):
        return jsonify({'error': 'Search directory not found'}), 404

    results = []
    query_lower = query.lower()

    try:
        for dirpath, dirnames, filenames in os.walk(full_path):
            for name in dirnames + filenames:
                if query_lower in name.lower():
                    entry_path = os.path.join(dirpath, name)
                    relative = os.path.relpath(entry_path, user_root)
                    stat = os.stat(entry_path)
                    results.append({
                        'name': name,
                        'path': relative,
                        'is_directory': os.path.isdir(entry_path),
                        'size_bytes': stat.st_size,
                        'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
                    })
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403

    return jsonify({
        'query': query,
        'total_results': len(results),
        'results': results,
    }), 200


